import React, { useState } from "react";

export default function Contact() {
  const email = "yairberger64@gmail.com";

  const [copied, setCopied] = useState(false);

  function handleCopy() {
    navigator.clipboard.writeText(email).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  }

  return (
    <section
      id="contact"
      className="section"
      style={{
        paddingLeft: "clamp(1.5rem, 8vw, 8rem)",
        paddingRight: "clamp(1.5rem, 8vw, 8rem)",
        borderTop: "1px solid #2C2C3E"
      }}
    >
      <div style={{ maxWidth: "640px" }}>
        {/* Eyebrow */}
        <p className="eyebrow mb-6">Contact</p>

        {/* Headline */}
        <h2
          style={{
            fontFamily: "'Space Grotesk', sans-serif",
            fontSize: "clamp(2rem, 5vw, 3.5rem)",
            fontWeight: 700,
            letterSpacing: "-0.03em",
            color: "#F0F0EC",
            lineHeight: 1.05,
            marginBottom: "1.5rem"
          }}
        >
          Let's build something that runs.
        </h2>

        {/* Body */}
        <p
          style={{
            fontFamily: "'Inter', sans-serif",
            fontSize: "1rem",
            color: "#8A8A9A",
            lineHeight: 1.75,
            maxWidth: "46ch",
            marginBottom: "2.5rem"
          }}
        >
          If you're hiring for an AI role, building something that needs
          agentic pipelines, or want to collaborate — reach out.
          I respond to every genuine message.
        </p>

        {/* Use cases */}
        <ul
          style={{
            listStyle: "none",
            display: "flex",
            flexDirection: "column",
            gap: "0.5rem",
            marginBottom: "3rem"
          }}
        >
          {[
            "AI / automation roles at forward-thinking companies",
            "Consulting on agentic system design",
            "AI workshops for marketing and ops teams",
            "Collaboration with other builders"
          ].map((item) => (
            <li
              key={item}
              style={{
                display: "flex",
                alignItems: "flex-start",
                gap: "0.75rem"
              }}
            >
              <span
                aria-hidden="true"
                style={{
                  fontFamily: "'JetBrains Mono', monospace",
                  fontSize: "0.7rem",
                  color: "#C8FF57",
                  marginTop: "0.2rem",
                  flexShrink: 0
                }}
              >
                →
              </span>
              <span
                style={{
                  fontFamily: "'Inter', sans-serif",
                  fontSize: "0.9rem",
                  color: "#8A8A9A"
                }}
              >
                {item}
              </span>
            </li>
          ))}
        </ul>

        {/* Email block */}
        <div
          className="card"
          style={{
            padding: "1.75rem 2rem",
            display: "flex",
            flexWrap: "wrap",
            alignItems: "center",
            justifyContent: "space-between",
            gap: "1.25rem"
          }}
        >
          <div>
            <p
              style={{
                fontFamily: "'JetBrains Mono', monospace",
                fontSize: "0.65rem",
                letterSpacing: "0.12em",
                textTransform: "uppercase",
                color: "#4A4A5E",
                marginBottom: "0.4rem"
              }}
            >
              Email
            </p>
            <p
              style={{
                fontFamily: "'Space Grotesk', sans-serif",
                fontWeight: 500,
                fontSize: "1rem",
                color: "#F0F0EC"
              }}
            >
              {email}
            </p>
          </div>

          <div style={{ display: "flex", gap: "0.75rem", flexWrap: "wrap" }}>
            {/* Primary: mailto */}
            <a
              href={`mailto:${email}`}
              style={{
                display: "inline-flex",
                alignItems: "center",
                gap: "0.4rem",
                fontFamily: "'Space Grotesk', sans-serif",
                fontWeight: 600,
                fontSize: "0.875rem",
                background: "#C8FF57",
                color: "#0A0A0F",
                padding: "0.6rem 1.25rem",
                borderRadius: "0.375rem",
                textDecoration: "none",
                whiteSpace: "nowrap",
                transition: "opacity 0.15s ease"
              }}
              onMouseEnter={e => e.currentTarget.style.opacity = "0.88"}
              onMouseLeave={e => e.currentTarget.style.opacity = "1"}
            >
              Send email →
            </a>

            {/* Secondary: copy */}
            <button
              onClick={handleCopy}
              style={{
                display: "inline-flex",
                alignItems: "center",
                gap: "0.4rem",
                fontFamily: "'JetBrains Mono', monospace",
                fontSize: "0.75rem",
                letterSpacing: "0.06em",
                background: "transparent",
                color: copied ? "#C8FF57" : "#8A8A9A",
                padding: "0.6rem 1.1rem",
                border: `1px solid ${copied ? "rgba(200,255,87,0.3)" : "#2C2C3E"}`,
                borderRadius: "0.375rem",
                cursor: "pointer",
                whiteSpace: "nowrap",
                transition: "all 0.15s ease"
              }}
            >
              {copied ? "Copied ✓" : "Copy address"}
            </button>
          </div>
        </div>
      </div>

      {/* Footer */}
      <footer
        style={{
          marginTop: "6rem",
          paddingTop: "2rem",
          borderTop: "1px solid #2C2C3E",
          display: "flex",
          flexWrap: "wrap",
          alignItems: "center",
          justifyContent: "space-between",
          gap: "1rem"
        }}
      >
        <p
          style={{
            fontFamily: "'JetBrains Mono', monospace",
            fontSize: "0.7rem",
            letterSpacing: "0.06em",
            color: "#4A4A5E"
          }}
        >
          Yair Berger · AI Systems Builder · {new Date().getFullYear()}
        </p>
        <a
          href="https://linkedin.com/in/yairberger"
          target="_blank"
          rel="noopener noreferrer"
          style={{
            fontFamily: "'JetBrains Mono', monospace",
            fontSize: "0.7rem",
            letterSpacing: "0.06em",
            color: "#4A4A5E",
            textDecoration: "none",
            transition: "color 0.15s ease"
          }}
          onMouseEnter={e => e.currentTarget.style.color = "#8A8A9A"}
          onMouseLeave={e => e.currentTarget.style.color = "#4A4A5E"}
        >
          LinkedIn →
        </a>
      </footer>
    </section>
  );
}
